// ============================================================
// INIT – Build run context shared across all subflows
// ============================================================
const runId = `run_${Date.now()}`;
const dryRun = $env['DRY_RUN'] === 'true';
const batchSize = parseInt($env['BATCH_SIZE'] || '50', 10);
const supabaseUrl = $env['SUPABASE_URL'];
const supabaseKey = $env['SUPABASE_SERVICE_ROLE_KEY'];
const pvgisBase = $env['PVGIS_BASE_URL'] || 'https://re.jrc.ec.europa.eu/api/v5_2';
const esiosToken = $env['ESIOS_API_TOKEN'];
const geoCsvUrl = $env['GEO_SOURCE_CSV_URL'] || 'https://raw.githubusercontent.com/inigoflores/ds-codigos-postales-ine-es/master/data/codigos_postales.csv';
const ibiJsonUrl = $env['IBI_ICIO_JSON_URL'] || '';
const compatCsvUrl = $env['COMPATIBILIDAD_CSV_URL'] || '';

if (!supabaseUrl || !supabaseKey) {
  throw new Error('SUPABASE_URL and SUPABASE_SERVICE_ROLE_KEY are required env vars');
}

const ctx = {
  runId,
  dryRun,
  batchSize,
  supabaseUrl,
  supabaseKey,
  pvgisBase,
  esiosToken,
  geoCsvUrl,
  ibiJsonUrl,
  compatCsvUrl,
  startedAt: new Date().toISOString(),
  stats: {
    geo: { fetched: 0, upserted: 0, errors: 0 },
    pvgis: { fetched: 0, upserted: 0, errors: 0, cached: 0 },
    esios: { fetched: 0, upserted: 0, errors: 0 },
    ibi: { fetched: 0, upserted: 0, errors: 0 },
    compatibilidad: { fetched: 0, upserted: 0, errors: 0 },
    rebuild: { municipios_energia: 0, pseo_url_index: 0, pseo_slug_index: 0 }
  },
  deadLetter: []
};

console.log(`[INIT] runId=${runId} dryRun=${dryRun} batchSize=${batchSize}`);
return [{ json: ctx }];

// ============================================================
// GEO – Parse CSV, slugify, deduplicate
// ============================================================
const ctx = $('Init Context').first().json;
const raw = $input.first().json;

// The HTTP node returns body as string for text/csv responses
const csvText = raw.data || raw.body || (typeof raw === 'string' ? raw : JSON.stringify(raw));

if (!csvText || typeof csvText !== 'string' || csvText.trim().length === 0) {
  throw new Error('GEO CSV response is empty or not a string');
}

function slugify(text) {
  // Normalize accents (basic map for Spanish)
  const map = {
    'á':'a','é':'e','í':'i','ó':'o','ú':'u','ü':'u','ñ':'n',
    'à':'a','è':'e','ì':'i','ò':'o','ù':'u',
    'Á':'a','É':'e','Í':'i','Ó':'o','Ú':'u','Ü':'u','Ñ':'n'
  };
  return text
    .toLowerCase()
    .split('').map(c => map[c] || c).join('')
    .replace(/[^a-z0-9\s-]/g, '')
    .trim()
    .replace(/[\s_]+/g, '-')
    .replace(/-+/g, '-');
}

const lines = csvText.split('\n').filter(l => l.trim());
if (lines.length < 2) throw new Error('GEO CSV has no data rows');

// Auto-detect delimiter
const delimiters = [';', ',', '\t', '|'];
let delimiter = ',';
const header = lines[0];
for (const d of delimiters) {
  if (header.split(d).length > 3) { delimiter = d; break; }
}

const headers = header.split(delimiter).map(h => h.trim().toLowerCase().replace(/["']/g, ''));

// Column index resolution – supports multiple CSV formats from INE/CNIG
const col = (names) => {
  for (const n of names) {
    const idx = headers.indexOf(n);
    if (idx !== -1) return idx;
  }
  return -1;
};

const iMun = col(['nmun','municipio','municipio_nombre','nombre_municipio','municipality']);
const iProv = col(['npro','provincia','provincia_nombre','nombre_provincia','province']);
const iCom = col(['ncom','comunidad','comunidad_autonoma','ccaa','region']);
const iLat = col(['lat','latitud','latitude','y','lat_wgs84']);
const iLon = col(['lon','longitud','longitude','x','lon_wgs84']);
const iCp = col(['cpro','cp','codigo_postal','postal_code','cpostal']);
const iPob = col(['pob','poblacion','population','habitantes']);

if (iMun === -1) throw new Error(`Could not find municipio column. Headers: ${headers.join(', ')}`);
if (iProv === -1) throw new Error(`Could not find provincia column. Headers: ${headers.join(', ')}`);

const seen = new Set();
const records = [];

for (let i = 1; i < lines.length; i++) {
  const parts = lines[i].split(delimiter).map(p => p.trim().replace(/^"|"$/g, ''));
  if (parts.length < Math.max(iMun, iProv) + 1) continue;

  const municipio = parts[iMun]?.trim();
  const provincia = parts[iProv]?.trim();
  if (!municipio || !provincia) continue;

  const slug = `/placas-solares/${slugify(municipio)}`;
  const key = `${municipio.toLowerCase()}::${provincia.toLowerCase()}`;
  if (seen.has(key)) continue;
  seen.add(key);

  const comunidad_autonoma = iCom >= 0 ? (parts[iCom]?.trim() || '') : '';
  const latitud = iLat >= 0 ? parseFloat(parts[iLat]) || null : null;
  const longitud = iLon >= 0 ? parseFloat(parts[iLon]) || null : null;
  const codigo_postal = iCp >= 0 ? (parts[iCp]?.trim() || null) : null;
  const poblacion = iPob >= 0 ? (parseInt(parts[iPob], 10) || null) : null;

  records.push({
    json: {
      municipio,
      provincia,
      comunidad_autonoma,
      latitud,
      longitud,
      codigo_postal,
      poblacion,
      slug,
      _ctx: ctx
    }
  });
}

console.log(`[GEO-PARSE] parsed=${records.length} unique municipalities`);
ctx.stats.geo.fetched = records.length;

return records;

// ============================================================
// GEO – Upsert batch to Supabase (municipios_dataset_es)
//        + slugs_seo_municipios_espana_es
// ============================================================
const items = $input.all();
if (!items.length) return [];

const ctx = items[0].json._ctx;
const { supabaseUrl, supabaseKey, dryRun, runId } = ctx;

const rows = items.map(i => ({
  municipio: i.json.municipio,
  provincia: i.json.provincia,
  comunidad_autonoma: i.json.comunidad_autonoma || '',
  poblacion: i.json.poblacion ?? null,
  latitud: i.json.latitud ?? null,
  longitud: i.json.longitud ?? null,
  codigo_postal: i.json.codigo_postal ?? null,
  slug: i.json.slug
}));

if (dryRun) {
  console.log(`[GEO-UPSERT][DRY-RUN] Would upsert ${rows.length} rows to municipios_dataset_es`);
  return [{ json: { stage: 'geo_upsert', dryRun: true, count: rows.length, runId } }];
}

// Helper: Supabase REST upsert with exponential backoff
async function supabaseUpsert(table, payload, onConflict, retries = 3) {
  const url = `${supabaseUrl}/rest/v1/${table}`;
  let lastErr;
  for (let attempt = 1; attempt <= retries; attempt++) {
    try {
      const response = await $http.post(url, payload, {
        headers: {
          'apikey': supabaseKey,
          'Authorization': `Bearer ${supabaseKey}`,
          'Content-Type': 'application/json',
          'Prefer': `resolution=merge-duplicates,return=minimal`
        },
        params: { on_conflict: onConflict }
      });
      return response;
    } catch (err) {
      lastErr = err;
      if (attempt < retries) {
        const delay = Math.pow(2, attempt) * 500;
        await new Promise(r => setTimeout(r, delay));
        console.warn(`[GEO-UPSERT] retry=${attempt} table=${table} err=${err.message}`);
      }
    }
  }
  throw lastErr;
}

try {
  await supabaseUpsert('municipios_dataset_es', rows, 'slug');
  ctx.stats.geo.upserted += rows.length;

  // Also upsert slugs table
  const slugRows = rows.map(r => ({ municipio: r.municipio, slug: r.slug }));
  await supabaseUpsert('slugs_seo_municipios_espana_es', slugRows, 'slug');

  console.log(`[GEO-UPSERT] batch upserted=${rows.length}`);
  return [{ json: { stage: 'geo_upsert', upserted: rows.length, runId } }];
} catch (err) {
  ctx.stats.geo.errors += rows.length;
  ctx.deadLetter.push({ stage: 'geo_upsert', error: err.message, batch: rows.length });
  console.error(`[GEO-UPSERT] ERROR: ${err.message}`);
  return [{ json: { stage: 'geo_upsert', error: err.message, runId } }];
}

// ============================================================
// PVGIS – Fetch municipalities with valid coordinates
//          from municipios_dataset_es via Supabase REST
// ============================================================
const ctx = $('Init Context').first().json;
const { supabaseUrl, supabaseKey } = ctx;

const url = `${supabaseUrl}/rest/v1/municipios_dataset_es?latitud=not.is.null&longitud=not.is.null&select=municipio,provincia,latitud,longitud&limit=10000`;

const response = await $http.get(url, {
  headers: {
    'apikey': supabaseKey,
    'Authorization': `Bearer ${supabaseKey}`
  }
});

const munis = Array.isArray(response) ? response : (response.data || []);

// Deduplicate by rounded province coordinates (aggregate per province)
// We only need one representative coord per province for PVGIS
const provinceMap = {};
for (const m of munis) {
  const prov = m.provincia;
  if (!prov) continue;
  if (!provinceMap[prov]) {
    provinceMap[prov] = {
      provincia: prov,
      lat: parseFloat(m.latitud),
      lon: parseFloat(m.longitud),
      count: 1
    };
  } else {
    // Running average for representative coordinate
    provinceMap[prov].lat = (provinceMap[prov].lat * provinceMap[prov].count + parseFloat(m.latitud)) / (provinceMap[prov].count + 1);
    provinceMap[prov].lon = (provinceMap[prov].lon * provinceMap[prov].count + parseFloat(m.longitud)) / (provinceMap[prov].count + 1);
    provinceMap[prov].count++;
  }
}

const provinces = Object.values(provinceMap).map(p => ({
  provincia: p.provincia,
  lat: Math.round(p.lat * 10000) / 10000,
  lon: Math.round(p.lon * 10000) / 10000,
  _ctx: ctx
}));

console.log(`[PVGIS-PREP] provinces_to_enrich=${provinces.length}`);
ctx.stats.pvgis.fetched = provinces.length;

return provinces.map(p => ({ json: p }));

// ============================================================
// PVGIS – Parse response + build radiacion_solar_provincial_es row
// ============================================================
const item = $input.first().json;
const ctx = item._ctx;

// item has provincia, lat, lon
// PVGIS response is in the previous node's output
const pvgisRaw = $('PVGIS – API Request').first().json;

let pvgisData = pvgisRaw;
// Handle nested body
if (pvgisRaw.data) pvgisData = pvgisRaw.data;
if (typeof pvgisData === 'string') {
  try { pvgisData = JSON.parse(pvgisData); } catch(e) {}
}

const outputs = pvgisData?.outputs;
const monthly = outputs?.monthly?.fixed || [];
const totals = outputs?.totals?.fixed;

if (!totals) {
  ctx.deadLetter.push({ stage: 'pvgis_parse', provincia: item.provincia, error: 'No totals in PVGIS response' });
  ctx.stats.pvgis.errors++;
  console.warn(`[PVGIS-PARSE] No totals for ${item.provincia}`);
  return [];
}

// E_y = annual production in kWh/kWp for 1kWp system
const produccion_media_panel_1kw = Math.round((totals.E_y || 0) * 10) / 10;
// H_year = yearly sum of irradiation kWh/m2/day * 365 ≈ H(i)_opt for annual
const irradiacion_kwh_m2 = Math.round((totals['H(i)_y'] || totals.H_year || totals['Hh:Gb(i)'] || 0) * 10) / 10;
// Estimated peak sun hours = annual kWh / 365
const horas_sol_anuales = Math.round(produccion_media_panel_1kw / 1.0);

const row = {
  provincia: item.provincia,
  horas_sol_anuales: horas_sol_anuales || 1800,
  irradiacion_kwh_m2: irradiacion_kwh_m2 || 1600,
  produccion_media_panel_1kw: produccion_media_panel_1kw || 1400,
  _ctx: ctx
};

console.log(`[PVGIS-PARSE] ${item.provincia}: E_y=${produccion_media_panel_1kw} H=${irradiacion_kwh_m2}`);
return [{ json: row }];

// ============================================================
// PVGIS – Upsert radiacion_solar_provincial_es
// ============================================================
const item = $input.first().json;
const ctx = item._ctx;
const { supabaseUrl, supabaseKey, dryRun } = ctx;

const row = {
  provincia: item.provincia,
  horas_sol_anuales: item.horas_sol_anuales,
  irradiacion_kwh_m2: item.irradiacion_kwh_m2,
  produccion_media_panel_1kw: item.produccion_media_panel_1kw
};

if (dryRun) {
  console.log(`[PVGIS-UPSERT][DRY-RUN] ${row.provincia}`);
  return [{ json: { stage: 'pvgis_upsert', dryRun: true, provincia: row.provincia } }];
}

async function upsertRow(table, payload, onConflict, retries = 3) {
  const url = `${supabaseUrl}/rest/v1/${table}`;
  let lastErr;
  for (let attempt = 1; attempt <= retries; attempt++) {
    try {
      return await $http.post(url, [payload], {
        headers: {
          'apikey': supabaseKey,
          'Authorization': `Bearer ${supabaseKey}`,
          'Content-Type': 'application/json',
          'Prefer': 'resolution=merge-duplicates,return=minimal'
        },
        params: { on_conflict: onConflict }
      });
    } catch(err) {
      lastErr = err;
      if (attempt < retries) await new Promise(r => setTimeout(r, Math.pow(2, attempt) * 600));
    }
  }
  throw lastErr;
}

try {
  await upsertRow('radiacion_solar_provincial_es', row, 'provincia');
  ctx.stats.pvgis.upserted++;
  return [{ json: { stage: 'pvgis_upsert', ok: true, provincia: row.provincia } }];
} catch(err) {
  ctx.stats.pvgis.errors++;
  ctx.deadLetter.push({ stage: 'pvgis_upsert', provincia: row.provincia, error: err.message });
  console.error(`[PVGIS-UPSERT] ERROR ${row.provincia}: ${err.message}`);
  return [{ json: { stage: 'pvgis_upsert', error: err.message, provincia: row.provincia } }];
}

// ============================================================
// ESIOS – Fetch electricity prices from Red Eléctrica API
// ============================================================
const ctx = $('Init Context').first().json;
const { esiosToken } = ctx;

if (!esiosToken) {
  console.warn('[ESIOS] No ESIOS_API_TOKEN set, skipping ESIOS ingest');
  return [{ json: { stage: 'esios_skip', reason: 'no_token' } }];
}

// Fetch last 7 days of PVPC indicator
const now = new Date();
const startDate = new Date(now);
startDate.setDate(startDate.getDate() - 7);

const startStr = startDate.toISOString().split('T')[0];
const endStr = now.toISOString().split('T')[0];
const indicatorId = $env['ESIOS_INDICATOR_ID'] || '10391';

const url = `https://api.esios.ree.es/indicators/${indicatorId}?start_date=${startStr}T00:00&end_date=${endStr}T23:59&time_trunc=day`;

let data;
try {
  const resp = await $http.get(url, {
    headers: {
      'x-api-key': esiosToken,
      'Accept': 'application/json; application/vnd.esios-api-v2+json',
      'Content-Type': 'application/json',
      'Host': 'api.esios.ree.es'
    }
  });
  data = resp.data || resp;
} catch(err) {
  ctx.stats.esios.errors++;
  ctx.deadLetter.push({ stage: 'esios_fetch', error: err.message });
  console.error(`[ESIOS-FETCH] ERROR: ${err.message}`);
  return [{ json: { stage: 'esios_fetch', error: err.message } }];
}

const values = data?.indicator?.values || data?.data?.values || [];
console.log(`[ESIOS-FETCH] received=${values.length} values`);
ctx.stats.esios.fetched = values.length;

return values.map(v => ({ json: { ...v, _ctx: ctx, _indicatorId: indicatorId } }));

// ============================================================
// ESIOS – Normalize + upsert to tarifas_electricas + precios_electricidad
// ============================================================
const items = $input.all();
if (!items.length) return [];

const first = items[0].json;
if (first.stage === 'esios_skip' || first.stage === 'esios_fetch') return items;

const ctx = first._ctx;
const { supabaseUrl, supabaseKey, dryRun } = ctx;

async function supabaseUpsert(table, payload, onConflict, retries = 3) {
  const url = `${supabaseUrl}/rest/v1/${table}`;
  let lastErr;
  for (let attempt = 1; attempt <= retries; attempt++) {
    try {
      return await $http.post(url, payload, {
        headers: {
          'apikey': supabaseKey,
          'Authorization': `Bearer ${supabaseKey}`,
          'Content-Type': 'application/json',
          'Prefer': 'resolution=merge-duplicates,return=minimal'
        },
        params: { on_conflict: onConflict }
      });
    } catch(err) {
      lastErr = err;
      if (attempt < retries) await new Promise(r => setTimeout(r, Math.pow(2, attempt) * 700));
    }
  }
  throw lastErr;
}

// 1) Ensure the tarifa exists
const tarifaCodigo = 'pvpc_2_0td';
const tarifaNombre = 'PVPC 2.0 TD – Precio Voluntario Pequeño Consumidor';

if (!dryRun) {
  try {
    await supabaseUpsert('tarifas_electricas_espana_es',
      [{ codigo: tarifaCodigo, nombre: tarifaNombre, tipo: 'regulada', ambito: 'nacional', activa: true }],
      'codigo'
    );
  } catch(err) {
    ctx.stats.esios.errors++;
    console.error(`[ESIOS-TARIFA] ${err.message}`);
  }
}

// 2) Daily aggregated prices (EUR/kWh)
const dailyMap = {};
for (const item of items) {
  const v = item.json;
  if (!v.datetime && !v.date) continue;
  const fecha = (v.datetime || v.date || '').split('T')[0];
  if (!fecha) continue;
  const valorMwh = parseFloat(v.value || v.precio || 0);
  const valorKwh = Math.round((valorMwh / 1000) * 100000) / 100000; // EUR/kWh 5 decimals
  if (!dailyMap[fecha]) dailyMap[fecha] = { total: 0, count: 0 };
  dailyMap[fecha].total += valorKwh;
  dailyMap[fecha].count++;
}

const priceRows = Object.entries(dailyMap).map(([fecha, agg]) => ({
  fecha,
  tarifa_codigo: tarifaCodigo,
  precio_kwh_media: Math.round((agg.total / agg.count) * 100000) / 100000,
  precio_kwh_min: null,
  precio_kwh_max: null,
  fuente: 'esios',
  indicador_id: first._indicatorId
}));

if (dryRun) {
  console.log(`[ESIOS-UPSERT][DRY-RUN] Would upsert ${priceRows.length} price rows`);
  return [{ json: { stage: 'esios_upsert', dryRun: true, count: priceRows.length } }];
}

try {
  if (priceRows.length) {
    await supabaseUpsert('precios_electricidad_es', priceRows, 'fecha,tarifa_codigo');
    ctx.stats.esios.upserted += priceRows.length;
  }
  console.log(`[ESIOS-UPSERT] upserted=${priceRows.length} daily price rows`);
  return [{ json: { stage: 'esios_upsert', upserted: priceRows.length } }];
} catch(err) {
  ctx.stats.esios.errors++;
  ctx.deadLetter.push({ stage: 'esios_upsert', error: err.message });
  console.error(`[ESIOS-UPSERT] ERROR: ${err.message}`);
  return [{ json: { stage: 'esios_upsert', error: err.message } }];
}

// ============================================================
// IBI – Fetch structured JSON from URL or env var
// Input JSON format: { items: [ { municipio, provincia,
//   ibi_pct, ibi_anos, icio_pct, icio_anos, fuente, url_fuente }, ... ] }
// ============================================================
const ctx = $('Init Context').first().json;
const { ibiJsonUrl, supabaseUrl, supabaseKey } = ctx;

let records = [];

if (!ibiJsonUrl) {
  console.warn('[IBI] No IBI_ICIO_JSON_URL configured, using empty set');
  return [{ json: { stage: 'ibi_skip', reason: 'no_url' } }];
}

try {
  const resp = await $http.get(ibiJsonUrl, {
    headers: { 'Accept': 'application/json' }
  });
  const data = resp.data || resp;
  records = Array.isArray(data) ? data : (data.items || []);
} catch(err) {
  ctx.deadLetter.push({ stage: 'ibi_fetch', error: err.message });
  console.error(`[IBI-FETCH] ERROR: ${err.message}`);
  return [{ json: { stage: 'ibi_fetch', error: err.message } }];
}

console.log(`[IBI-FETCH] fetched=${records.length} records`);
ctx.stats.ibi.fetched = records.length;

return records.map(r => ({ json: { ...r, _ctx: ctx } }));

// ============================================================
// IBI – Validate, normalize and upsert
//   bonificaciones_ibi_municipios_es  (on_conflict: municipio, provincia)
//   bonificaciones_icio_municipios_es (on_conflict: municipio, provincia)
// ============================================================
const items = $input.all();
if (!items.length) return [];

const first = items[0].json;
if (first.stage === 'ibi_skip' || first.stage === 'ibi_fetch') return items;

const ctx = first._ctx;
const { supabaseUrl, supabaseKey, dryRun } = ctx;

async function supabaseUpsert(table, payload, onConflict, retries = 3) {
  const url = `${supabaseUrl}/rest/v1/${table}`;
  let lastErr;
  for (let attempt = 1; attempt <= retries; attempt++) {
    try {
      return await $http.post(url, payload, {
        headers: {
          'apikey': supabaseKey,
          'Authorization': `Bearer ${supabaseKey}`,
          'Content-Type': 'application/json',
          'Prefer': 'resolution=merge-duplicates,return=minimal'
        },
        params: { on_conflict: onConflict }
      });
    } catch(err) {
      lastErr = err;
      if (attempt < retries) await new Promise(r => setTimeout(r, Math.pow(2, attempt) * 600));
    }
  }
  throw lastErr;
}

const ibiRows = [];
const icioRows = [];
const deadItems = [];

for (const item of items) {
  const r = item.json;
  if (!r.municipio || !r.provincia) {
    deadItems.push({ ...r, _dead_reason: 'missing municipio or provincia' });
    continue;
  }
  if (r.ibi_pct != null) {
    ibiRows.push({
      municipio: r.municipio,
      provincia: r.provincia,
      porcentaje_bonificacion: parseFloat(r.ibi_pct) || 0,
      anos_bonificacion: parseInt(r.ibi_anos, 10) || null,
      descripcion: r.descripcion_ibi || null,
      fuente: r.fuente || null,
      url_fuente: r.url_fuente || null
    });
  }
  if (r.icio_pct != null) {
    icioRows.push({
      municipio: r.municipio,
      provincia: r.provincia,
      porcentaje_bonificacion: parseFloat(r.icio_pct) || 0,
      anos_bonificacion: parseInt(r.icio_anos, 10) || null,
      descripcion: r.descripcion_icio || null,
      fuente: r.fuente || null,
      url_fuente: r.url_fuente || null
    });
  }
}

if (deadItems.length) {
  ctx.deadLetter.push(...deadItems.map(d => ({ stage: 'ibi_validate', ...d })));
  ctx.stats.ibi.errors += deadItems.length;
  console.warn(`[IBI-UPSERT] dead_items=${deadItems.length}`);
}

if (dryRun) {
  console.log(`[IBI-UPSERT][DRY-RUN] ibi=${ibiRows.length} icio=${icioRows.length}`);
  return [{ json: { stage: 'ibi_upsert', dryRun: true, ibi: ibiRows.length, icio: icioRows.length } }];
}

try {
  if (ibiRows.length) await supabaseUpsert('bonificaciones_ibi_municipios_es', ibiRows, 'municipio,provincia');
  if (icioRows.length) await supabaseUpsert('bonificaciones_icio_municipios_es', icioRows, 'municipio,provincia');
