// COMPATIBILIDAD – Fetch CSV from URL or env
// Expected columns: inversor, bateria, cargador_ev, compatible
// ============================================================
const ctx = $('Init Context').first().json;
const { compatCsvUrl } = ctx;

if (!compatCsvUrl) {
  console.warn('[COMPAT] No COMPATIBILIDAD_CSV_URL configured, skipping');
  return [{ json: { stage: 'compat_skip', reason: 'no_url' } }];
}

let csvText;
try {
  const resp = await $http.get(compatCsvUrl);
  csvText = resp.data || resp.body || (typeof resp === 'string' ? resp : null);
} catch(err) {
  ctx.deadLetter.push({ stage: 'compat_fetch', error: err.message });
  console.error(`[COMPAT-FETCH] ERROR: ${err.message}`);
  return [{ json: { stage: 'compat_fetch', error: err.message } }];
}

if (!csvText || typeof csvText !== 'string') {
  return [{ json: { stage: 'compat_fetch', error: 'empty CSV response' } }];
}

function normalizeBool(val) {
  if (val == null) return true;
  const s = String(val).toLowerCase().trim();
  return ['1','true','si','sí','yes','compatible','ok'].includes(s);
}

const lines = csvText.split('\n').filter(l => l.trim());
const delimiter = lines[0].includes(';') ? ';' : ',';
const headers = lines[0].split(delimiter).map(h => h.trim().toLowerCase().replace(/["']/g, ''));

const iInv = headers.indexOf('inversor');
const iBat = headers.indexOf('bateria');
const iCarg = headers.indexOf('cargador_ev');
const iComp = headers.findIndex(h => ['compatible','compatibilidad'].includes(h));

if (iInv === -1 || iBat === -1 || iCarg === -1) {
  throw new Error(`COMPAT CSV missing required columns. Headers: ${headers.join(', ')}`);
}

const records = [];
for (let i = 1; i < lines.length; i++) {
  const parts = lines[i].split(delimiter).map(p => p.trim().replace(/^"|"$/g, ''));
  if (parts.length < 3) continue;
  const inversor = parts[iInv];
  const bateria = parts[iBat];
  const cargador_ev = parts[iCarg];
  const compatible = iComp >= 0 ? normalizeBool(parts[iComp]) : true;
  if (!inversor || !bateria || !cargador_ev) continue;
  records.push({ json: { inversor, bateria, cargador_ev, compatible, _ctx: ctx } });
}

console.log(`[COMPAT-PARSE] parsed=${records.length} rows`);
ctx.stats.compatibilidad.fetched = records.length;
return records;

