//   on_conflict: (inversor, bateria, cargador_ev)
// ============================================================
const items = $input.all();
if (!items.length) return [];

const first = items[0].json;
if (first.stage === 'compat_skip' || first.stage === 'compat_fetch') return items;

const ctx = first._ctx;
const { supabaseUrl, supabaseKey, dryRun } = ctx;

const rows = items.map(i => ({
  inversor: i.json.inversor,
  bateria: i.json.bateria,
  cargador_ev: i.json.cargador_ev,
  compatible: i.json.compatible
}));

if (dryRun) {
  console.log(`[COMPAT-UPSERT][DRY-RUN] Would upsert ${rows.length} rows`);
  return [{ json: { stage: 'compat_upsert', dryRun: true, count: rows.length } }];
}

async function supabaseUpsert(table, payload, onConflict, retries = 3) {
  const url = `${supabaseUrl}/rest/v1/${table}`;
  let lastErr;
  for (let attempt = 1; attempt <= retries; attempt++) {
    try {
      return await $http.post(url, payload, {
        headers: {
          'apikey': supabaseKey,
          'Authorization': `Bearer ${supabaseKey}`,
          'Content-Type': 'application/json',
          'Prefer': 'resolution=merge-duplicates,return=minimal'
        },
        params: { on_conflict: onConflict }
      });
    } catch(err) {
      lastErr = err;
      if (attempt < retries) await new Promise(r => setTimeout(r, Math.pow(2, attempt) * 600));
    }
  }
  throw lastErr;
}

try {
  await supabaseUpsert('compatibilidad_inversor_bateria_cargador_ev_es', rows, 'inversor,bateria,cargador_ev');
  ctx.stats.compatibilidad.upserted += rows.length;
  console.log(`[COMPAT-UPSERT] upserted=${rows.length}`);
  return [{ json: { stage: 'compat_upsert', upserted: rows.length } }];
} catch(err) {
  ctx.stats.compatibilidad.errors += rows.length;
  ctx.deadLetter.push({ stage: 'compat_upsert', error: err.message, count: rows.length });
  console.error(`[COMPAT-UPSERT] ERROR: ${err.message}`);
  return [{ json: { stage: 'compat_upsert', error: err.message } }];
}

